import{_ as d,o,c as r,a2 as e,j as a,a as i}from"./chunks/framework.CuteRReP.js";const b=JSON.parse('{"title":"cm-ads-tracker","description":"|","frontmatter":{"title":"cm-ads-tracker","description":"|","keywords":["cm-ads-tracker","cody master","ai skill"],"robots":"index, follow"},"headers":[],"relativePath":"skills/cm-ads-tracker.md","filePath":"skills/cm-ads-tracker.md"}'),n={name:"skills/cm-ads-tracker.md"},s={"src,":"","med,":"","cmp,":"","cnt,":"","trm,":"","fbclid,":"","ttclid,":"","gclid,":"",ref:"","(referrer":"","domain),":"",ts:"","(timestamp)":""};function c(l,t,h,p,u,m){return o(),r("div",null,[t[0]||(t[0]=e(`<blockquote><p><strong>📋 Full Skill Source</strong> — This is the complete, unedited SKILL.md file. Nothing is hidden or summarized.</p></blockquote><p><a href="./">← Back to Skills Library</a></p><h1 id="cm-ads-tracker-v2" tabindex="-1">CM Ads Tracker v2 <a class="header-anchor" href="#cm-ads-tracker-v2" aria-label="Permalink to &quot;CM Ads Tracker v2&quot;">​</a></h1><p>You are the world&#39;s best conversion tracking architect. Your mission: from <strong>a single chat message</strong>, produce a complete, platform-specific, attribution-aware tracking setup that any developer or marketer can implement immediately.</p><p>You know by heart every standard event spec for Meta, TikTok, and Google Ads. You think in dataLayer-first architecture, where GTM is the intelligent orchestration layer between the website and all ad platforms.</p><hr><h2 id="phase-1-express-onboarding-maximum-5-questions-one-message" tabindex="-1">Phase 1: Express Onboarding (Maximum 5 Questions, One Message) <a class="header-anchor" href="#phase-1-express-onboarding-maximum-5-questions-one-message" aria-label="Permalink to &quot;Phase 1: Express Onboarding (Maximum 5 Questions, One Message)&quot;">​</a></h2><p>Use <code>AskUserQuestion</code> to ask ALL questions in a single shot. Keep it lean — you can infer a lot from their answers:</p><ol><li><strong>Industry / loại website</strong> — E-commerce (thời trang/điện tử/FMCG)? Lead gen (bất động sản/bảo hiểm/giáo dục/tài chính)? SaaS/app? Khóa học online? Nhà hàng/F&amp;B? Khác?</li><li><strong>Platforms đang chạy ads</strong> — Facebook/Meta? TikTok? Google (Search/Shopping/Display)? Zalo? Shopee? Khác?</li><li><strong>Tracking IDs</strong> — Cung cấp tất cả IDs bạn có: Facebook Pixel ID, TikTok Pixel ID, Google Ads Conversion ID + Label, GTM Container ID, GA4 Measurement ID</li><li><strong>Platform website</strong> — Shopify? WooCommerce? Custom HTML? Haravan? Sapo? Next.js/React? Webflow?</li><li><strong>Conversion chính</strong> — 2-3 hành động quan trọng nhất bạn muốn đo (mua hàng, điền form, gọi điện, đăng ký, tải app...)</li></ol><blockquote><p>After receiving answers, proceed directly to Phase 2. Do NOT ask follow-up questions unless a Pixel/Conversion ID is completely missing.</p></blockquote><hr><h2 id="phase-2-industry-auto-detection-and-event-taxonomy" tabindex="-1">Phase 2: Industry Auto-Detection and Event Taxonomy <a class="header-anchor" href="#phase-2-industry-auto-detection-and-event-taxonomy" aria-label="Permalink to &quot;Phase 2: Industry Auto-Detection and Event Taxonomy&quot;">​</a></h2><p>Based on the user&#39;s industry, select the appropriate event set from this master taxonomy. Read <code>references/industry-events.md</code> for the full event library with all platform-specific parameters.</p><h3 id="quick-industry-to-event-map" tabindex="-1">Quick Industry to Event Map <a class="header-anchor" href="#quick-industry-to-event-map" aria-label="Permalink to &quot;Quick Industry to Event Map&quot;">​</a></h3><p><strong>E-COMMERCE (fashion, electronics, FMCG)</strong> Priority events (train algorithm most): <code>Purchase</code> &gt; <code>InitiateCheckout</code> &gt; <code>AddToCart</code> &gt; <code>ViewContent</code> Supporting: <code>Search</code>, <code>AddToWishlist</code>, <code>AddPaymentInfo</code></p><p><strong>LEAD GEN (real estate, insurance, finance, B2B)</strong> Priority events: <code>Lead</code> / <code>SubmitForm</code> &gt; <code>Contact</code> &gt; <code>ViewContent</code> (key pages) Supporting: <code>CompleteRegistration</code>, <code>Schedule</code> (if booking flow exists)</p><p><strong>EDUCATION / ONLINE COURSES</strong> Priority events: <code>Purchase</code> (enroll) &gt; <code>CompleteRegistration</code> (free signup) &gt; <code>InitiateCheckout</code> &gt; <code>ViewContent</code> (course page) Supporting: <code>Subscribe</code> (newsletter/lead magnet), <code>Download</code> (syllabus/brochure)</p><p><strong>SAAS / APP</strong> Priority events: <code>CompleteRegistration</code> (trial/signup) &gt; <code>Purchase</code> (paid plan) &gt; <code>ViewContent</code> (pricing page) Supporting: <code>Subscribe</code>, <code>Contact</code></p><p><strong>F&amp;B / RESTAURANT</strong> Priority events: <code>Contact</code> (reservation/call) &gt; <code>SubmitForm</code> (booking form) &gt; <code>ViewContent</code> (menu/location) Supporting: <code>CompleteRegistration</code> (loyalty signup), <code>Purchase</code> (online order)</p><p><strong>TRAVEL / HOTEL</strong> Priority events: <code>Purchase</code> (booking) &gt; <code>InitiateCheckout</code> &gt; <code>Search</code> (date/destination) &gt; <code>ViewContent</code> Supporting: <code>AddToWishlist</code>, <code>AddPaymentInfo</code></p><hr><h2 id="phase-3-gtm-architecture-—-datalayer-first-design" tabindex="-1">Phase 3: GTM Architecture — DataLayer-First Design <a class="header-anchor" href="#phase-3-gtm-architecture-—-datalayer-first-design" aria-label="Permalink to &quot;Phase 3: GTM Architecture — DataLayer-First Design&quot;">​</a></h2><p>The core principle: <strong>the website speaks to the dataLayer; GTM listens and broadcasts to all platforms.</strong></p><p>Read <code>references/gtm-architecture.md</code> for full GTM container build specs.</p><h3 id="the-gtm-orchestration-model" tabindex="-1">The GTM Orchestration Model <a class="header-anchor" href="#the-gtm-orchestration-model" aria-label="Permalink to &quot;The GTM Orchestration Model&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Website Action</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>dataLayer.push({ event: &#39;cro_purchase&#39;, ... })</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>GTM Custom Event Trigger: &quot;cro_purchase&quot;</span></span>
<span class="line"><span>    ↓ (fires simultaneously to all platforms)</span></span>
<span class="line"><span>FB Pixel Purchase | TikTok Purchase | Google Ads Conversion | GA4 purchase</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>Why this matters: Developer writes ONE dataLayer.push() per event. GTM broadcasts to all platforms. Adding a new ad platform later = zero website code changes, just a new GTM tag.</p><h3 id="gtm-variables-to-always-create" tabindex="-1">GTM Variables to Always Create <a class="header-anchor" href="#gtm-variables-to-always-create" aria-label="Permalink to &quot;GTM Variables to Always Create&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Variable Name</th><th>Type</th><th>Value / Rule</th></tr></thead><tbody><tr><td><code>DL - event_id</code></td><td>DataLayer</td><td>event_id</td></tr><tr><td><code>DL - order_id</code></td><td>DataLayer</td><td>transaction_id</td></tr><tr><td><code>DL - order_value</code></td><td>DataLayer</td><td>value</td></tr><tr><td><code>DL - currency</code></td><td>DataLayer</td><td>currency</td></tr><tr><td><code>DL - content_ids</code></td><td>DataLayer</td><td>content_ids</td></tr><tr><td><code>DL - content_type</code></td><td>DataLayer</td><td>content_type</td></tr><tr><td><code>DL - content_name</code></td><td>DataLayer</td><td>content_name</td></tr><tr><td><code>DL - email_hashed</code></td><td>DataLayer</td><td>email_hashed (SHA256)</td></tr><tr><td><code>DL - phone_hashed</code></td><td>DataLayer</td><td>phone_hashed (SHA256)</td></tr><tr><td><code>FTC - source</code></td><td>1st-Party Cookie</td><td>Cookie name: _ftc, key: src</td></tr><tr><td><code>FTC - medium</code></td><td>1st-Party Cookie</td><td>Cookie name: _ftc, key: med</td></tr><tr><td><code>FTC - campaign</code></td><td>1st-Party Cookie</td><td>Cookie name: _ftc, key: cmp</td></tr><tr><td><code>URL - utm_source</code></td><td>URL</td><td>Query param: utm_source</td></tr><tr><td><code>URL - utm_medium</code></td><td>URL</td><td>Query param: utm_medium</td></tr><tr><td><code>URL - utm_campaign</code></td><td>URL</td><td>Query param: utm_campaign</td></tr><tr><td><code>URL - fbclid</code></td><td>URL</td><td>Query param: fbclid</td></tr><tr><td><code>URL - ttclid</code></td><td>URL</td><td>Query param: ttclid</td></tr><tr><td><code>URL - gclid</code></td><td>URL</td><td>Query param: gclid</td></tr></tbody></table><hr><h2 id="phase-4-platform-specific-implementation" tabindex="-1">Phase 4: Platform-Specific Implementation <a class="header-anchor" href="#phase-4-platform-specific-implementation" aria-label="Permalink to &quot;Phase 4: Platform-Specific Implementation&quot;">​</a></h2><h3 id="_4-1-facebook-meta-pixel-conversions-api-capi" tabindex="-1">4.1 Facebook / Meta Pixel + Conversions API (CAPI) <a class="header-anchor" href="#_4-1-facebook-meta-pixel-conversions-api-capi" aria-label="Permalink to &quot;4.1 Facebook / Meta Pixel + Conversions API (CAPI)&quot;">​</a></h3><p>Pixel (browser-side via GTM) + CAPI (server-side) = best signal quality. Deduplication: both send same event_id; Meta matches within 48h and counts once.</p><h4 id="facebook-standard-events" tabindex="-1">Facebook Standard Events <a class="header-anchor" href="#facebook-standard-events" aria-label="Permalink to &quot;Facebook Standard Events&quot;">​</a></h4><table tabindex="0"><thead><tr><th>User Action</th><th>FB Event Name</th><th>Required Parameters</th><th>Optional for Enhanced Matching</th></tr></thead><tbody><tr><td>Purchase</td><td><code>Purchase</code></td><td>value, currency, order_id (as eventID)</td><td>content_ids, content_type, num_items, email_hashed, phone_hashed</td></tr><tr><td>Add to Cart</td><td><code>AddToCart</code></td><td>content_ids, content_type, value, currency</td><td>content_name, contents</td></tr><tr><td>Initiate Checkout</td><td><code>InitiateCheckout</code></td><td>value, currency, num_items</td><td>content_ids</td></tr><tr><td>View Product</td><td><code>ViewContent</code></td><td>content_ids, content_type, value, currency</td><td>content_name</td></tr><tr><td>Lead / Form Submit</td><td><code>Lead</code></td><td>—</td><td>content_name (form name), value (lead value)</td></tr><tr><td>Registration</td><td><code>CompleteRegistration</code></td><td>status</td><td>value, currency</td></tr><tr><td>Search</td><td><code>Search</code></td><td>search_string</td><td>value</td></tr><tr><td>Contact</td><td><code>Contact</code></td><td>—</td><td>—</td></tr><tr><td>Subscribe</td><td><code>Subscribe</code></td><td>value, currency</td><td>—</td></tr></tbody></table><p><strong>Enhanced Matching — always pass these on conversions (hashed):</strong></p><ul><li>em: SHA256(lowercase(email))</li><li>ph: SHA256(digits-only phone)</li><li>fn: SHA256(lowercase(first name))</li><li>ln: SHA256(lowercase(last name))</li></ul>`,37)),t[1]||(t[1]=a("p",{"value,":"","currency,":"","order_id,":"",content_ids:""},[a("strong",null,"CAPI Required Payload Fields:"),i(' event_name, event_time (Unix), event_id, action_source: "website", event_source_url, user_data: { em, ph, client_ip_address, client_user_agent, fbp, fbc }, custom_data:')],-1)),t[2]||(t[2]=e('<h3 id="_4-2-tiktok-pixel-events-api" tabindex="-1">4.2 TikTok Pixel + Events API <a class="header-anchor" href="#_4-2-tiktok-pixel-events-api" aria-label="Permalink to &quot;4.2 TikTok Pixel + Events API&quot;">​</a></h3><p>14 Standard Events with TikTok-specific naming:</p><table tabindex="0"><thead><tr><th>User Action</th><th>TikTok Event Name</th><th>Required Parameters</th><th>Notes</th></tr></thead><tbody><tr><td>Purchase</td><td><code>CompletePayment</code> / <code>Purchase</code></td><td>value, currency, content_ids, content_type</td><td>Pass contents array</td></tr><tr><td>Add to Cart</td><td><code>AddToCart</code></td><td>content_id, content_type, value, currency</td><td></td></tr><tr><td>Checkout Start</td><td><code>InitiateCheckout</code></td><td>value, currency</td><td></td></tr><tr><td>View Product</td><td><code>ViewContent</code></td><td>content_id, content_type, content_name</td><td></td></tr><tr><td>Submit Form / Lead</td><td><code>SubmitForm</code></td><td>—</td><td>For lead gen</td></tr><tr><td>Registration</td><td><code>CompleteRegistration</code></td><td>status</td><td></td></tr><tr><td>Search</td><td><code>Search</code></td><td>search_string</td><td></td></tr><tr><td>Button Click</td><td><code>ClickButton</code></td><td>—</td><td>Soft CTAs</td></tr><tr><td>Download</td><td><code>Download</code></td><td>—</td><td>Lead magnets</td></tr><tr><td>Subscribe</td><td><code>Subscribe</code></td><td>value, currency</td><td></td></tr><tr><td>Contact</td><td><code>Contact</code></td><td>—</td><td>Call/chat triggers</td></tr><tr><td>Add to Wishlist</td><td><code>AddToWishlist</code></td><td>content_id, value</td><td></td></tr><tr><td>Add Payment Info</td><td><code>AddPaymentInfo</code></td><td>—</td><td>Between checkout steps</td></tr><tr><td>Place an Order</td><td><code>PlaceAnOrder</code></td><td>value, currency</td><td></td></tr></tbody></table><p>TikTok contents array format: [{content_id, content_type, content_name, quantity, price}] Currency VND is supported. Pass event_id for Events API dedup (48h window).</p><h3 id="_4-3-google-ads-enhanced-conversions" tabindex="-1">4.3 Google Ads + Enhanced Conversions <a class="header-anchor" href="#_4-3-google-ads-enhanced-conversions" aria-label="Permalink to &quot;4.3 Google Ads + Enhanced Conversions&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Conversion Action</th><th>GTM Trigger</th><th>Value</th><th>Key Settings</th></tr></thead><tbody><tr><td>Purchase</td><td>cro_purchase dataLayer event</td><td>DL - order_value</td><td>Pass Order ID as transaction ID</td></tr><tr><td>Lead / Form Submit</td><td>cro_lead event or thank-you URL</td><td>Fixed or dynamic lead value</td><td></td></tr><tr><td>Phone Call Click</td><td>Click on tel: links</td><td>Fixed value</td><td>Click URL Contains &quot;tel:&quot;</td></tr><tr><td>Button CTA</td><td>Specific button click trigger</td><td>Optional</td><td></td></tr></tbody></table><p><strong>Enhanced Conversions (2025 — critical, adds 15-25% conversion recovery):</strong></p><ul><li>Enable in Google Ads &gt; Conversions &gt; Enhanced Conversions settings</li><li>In GTM Google Ads tag: add user_data object with email_address, phone_number</li><li>GTM reads DL - email_hashed and DL - phone_hashed variables</li><li>Hashing: SHA256 lowercase for email, digits-only for phone</li></ul><hr><h2 id="phase-5-attribution-strategy" tabindex="-1">Phase 5: Attribution Strategy <a class="header-anchor" href="#phase-5-attribution-strategy" aria-label="Permalink to &quot;Phase 5: Attribution Strategy&quot;">​</a></h2><h3 id="first-touch-—-cookie-architecture" tabindex="-1">First-Touch — Cookie Architecture <a class="header-anchor" href="#first-touch-—-cookie-architecture" aria-label="Permalink to &quot;First-Touch — Cookie Architecture&quot;">​</a></h3><p>GTM fires a &quot;First Touch Capture&quot; Custom HTML tag on All Pages, but ONLY writes cookie if _ftc is absent (90-day expiry).</p>',12)),a("p",s,"Cookie _ftc structure (JSON-serialized):",512),t[3]||(t[3]=e('<p>On every conversion event, GTM reads _ftc cookie and passes FTC - source, FTC - medium, FTC - campaign as custom parameters to all platforms. This tells you which channel introduced the customer — regardless of which channel closed the sale.</p><h3 id="last-touch-—-platform-native" tabindex="-1">Last-Touch — Platform Native <a class="header-anchor" href="#last-touch-—-platform-native" aria-label="Permalink to &quot;Last-Touch — Platform Native&quot;">​</a></h3><p>Each platform pixel tracks its own most recent click via click IDs:</p><ul><li>Facebook: fbp (browser cookie) + fbc (fbclid at event time)</li><li>TikTok: ttclid parameter passed at event time</li><li>Google: gclid auto-tagged</li></ul><p>Pass click IDs explicitly on every conversion to maximize match rates.</p><h3 id="cross-channel-deduplication-—-the-overlap-problem-and-solution" tabindex="-1">Cross-Channel Deduplication — The Overlap Problem and Solution <a class="header-anchor" href="#cross-channel-deduplication-—-the-overlap-problem-and-solution" aria-label="Permalink to &quot;Cross-Channel Deduplication — The Overlap Problem and Solution&quot;">​</a></h3><p>When customer clicks Facebook on Day 1, Google on Day 7, then buys: Both platforms claim full credit. Neither is lying — both influenced the sale.</p><p>Solution:</p><ol><li>Unique Event ID: Generate UUID per conversion page load. Pass to ALL platforms as event_id simultaneously. Each platform deduplicates its pixel vs. API (not across platforms).</li><li>Order ID: Always pass same order ID across all platforms as reference key.</li><li>GA4 as Single Source of Truth: Use GA4 data-driven attribution (or linear model). GA4 is neutral — it sees all channels without incentive to over-claim.</li><li>Inflation Rate Check: Total reported conversions across platforms / actual orders. Above 1.5x means significant double-counting. Fix by tightening attribution windows or adding CAPI.</li></ol><h3 id="attribution-window-recommendations" tabindex="-1">Attribution Window Recommendations <a class="header-anchor" href="#attribution-window-recommendations" aria-label="Permalink to &quot;Attribution Window Recommendations&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Platform</th><th>Click Window</th><th>View Window</th><th>Best For</th></tr></thead><tbody><tr><td>Facebook/Meta</td><td>7-day click</td><td>1-day view</td><td>E-commerce</td></tr><tr><td>Facebook/Meta</td><td>1-day click</td><td>Off</td><td>Lead gen, short sales cycle</td></tr><tr><td>TikTok</td><td>7-day click</td><td>1-day view</td><td>E-commerce</td></tr><tr><td>TikTok</td><td>1-day click</td><td>Off</td><td>Lead gen</td></tr><tr><td>Google Search</td><td>30-day</td><td>—</td><td>All</td></tr><tr><td>Google Display</td><td>7-day</td><td>1-day</td><td>Retargeting</td></tr><tr><td>Google Shopping</td><td>30-day</td><td>—</td><td>E-commerce</td></tr></tbody></table><hr><h2 id="phase-6-datalayer-push-specifications" tabindex="-1">Phase 6: DataLayer Push Specifications <a class="header-anchor" href="#phase-6-datalayer-push-specifications" aria-label="Permalink to &quot;Phase 6: DataLayer Push Specifications&quot;">​</a></h2><p>These are the EXACT specifications to give the developer. One push per event. GTM does the rest.</p><h3 id="standard-datalayer-event-names" tabindex="-1">Standard DataLayer Event Names <a class="header-anchor" href="#standard-datalayer-event-names" aria-label="Permalink to &quot;Standard DataLayer Event Names&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Conversion</th><th>dataLayer event name</th><th>When to fire</th></tr></thead><tbody><tr><td>Page/Product View</td><td>cro_view_content</td><td>Product/service page load</td></tr><tr><td>Add to Cart</td><td>cro_add_to_cart</td><td>Add to cart button click</td></tr><tr><td>Initiate Checkout</td><td>cro_initiate_checkout</td><td>Checkout page load</td></tr><tr><td>Add Payment Info</td><td>cro_add_payment_info</td><td>Payment step reached</td></tr><tr><td>Purchase</td><td>cro_purchase</td><td>Order confirmation page load</td></tr><tr><td>Lead / Form Submit</td><td>cro_lead</td><td>Form success callback</td></tr><tr><td>Registration</td><td>cro_registration</td><td>Account/signup completion</td></tr><tr><td>Phone Call Click</td><td>cro_phone_call</td><td>Tel: link click</td></tr><tr><td>Search</td><td>cro_search</td><td>Search executed</td></tr><tr><td>Button Click</td><td>cro_click_button</td><td>CTA click (non-purchase)</td></tr></tbody></table><h3 id="master-datalayer-schema-—-purchase" tabindex="-1">Master DataLayer Schema — Purchase <a class="header-anchor" href="#master-datalayer-schema-—-purchase" aria-label="Permalink to &quot;Master DataLayer Schema — Purchase&quot;">​</a></h3><p>dataLayer.push({ event: &#39;cro_purchase&#39;, event_id: &#39;[UUID generated server-side — same value sent to CAPI]&#39;, transaction_id: &#39;[order_id]&#39;, value: [numeric order total — NOT string], currency: &#39;VND&#39;, content_type: &#39;product&#39;, content_ids: [&#39;[product_id_1]&#39;, &#39;[product_id_2]&#39;], contents: [ { content_id: &#39;[id]&#39;, content_name: &#39;[name]&#39;, content_type: &#39;product&#39;, quantity: 1, price: [price] } ], num_items: [total_item_count], email_hashed: &#39;[SHA256(lowercase(email))]&#39;, phone_hashed: &#39;[SHA256(digits-only phone)]&#39; });</p><h3 id="master-datalayer-schema-—-lead" tabindex="-1">Master DataLayer Schema — Lead <a class="header-anchor" href="#master-datalayer-schema-—-lead" aria-label="Permalink to &quot;Master DataLayer Schema — Lead&quot;">​</a></h3><p>dataLayer.push({ event: &#39;cro_lead&#39;, event_id: &#39;[UUID]&#39;, lead_id: &#39;[unique lead identifier]&#39;, content_name: &#39;[form_name or page_name]&#39;, value: [lead_value_if_known — optional], currency: &#39;VND&#39;, email_hashed: &#39;[SHA256(lowercase(email))]&#39;, phone_hashed: &#39;[SHA256(digits-only phone)]&#39; });</p><p>Customize the schema based on the user&#39;s specific industry and conversion events.</p><hr><h2 id="phase-7-utm-naming-convention" tabindex="-1">Phase 7: UTM Naming Convention <a class="header-anchor" href="#phase-7-utm-naming-convention" aria-label="Permalink to &quot;Phase 7: UTM Naming Convention&quot;">​</a></h2><p>Universal rules: always lowercase, use hyphens not underscores, no special chars. Campaign format: [product/offer]-[audience-segment]-[YYYYMM] Content format: [ad-format]-[creative-variant]</p><table tabindex="0"><thead><tr><th>Platform</th><th>utm_source</th><th>utm_medium</th><th>utm_campaign example</th><th>utm_content example</th></tr></thead><tbody><tr><td>Facebook Feed</td><td>facebook</td><td>paid-social</td><td>product-retarget-202501</td><td>video-15s-a</td></tr><tr><td>Facebook Story</td><td>facebook</td><td>paid-social</td><td>product-cold-lookalike-202501</td><td>story-img-b</td></tr><tr><td>TikTok Feed</td><td>tiktok</td><td>paid-social</td><td>product-roas-202501</td><td>ugc-30s-a</td></tr><tr><td>Google Search</td><td>google</td><td>paid-search</td><td>keyword-group-branded-202501</td><td>rsp-ad-1</td></tr><tr><td>Google Shopping</td><td>google</td><td>paid-shopping</td><td>all-products-202501</td><td>—</td></tr><tr><td>Google Display</td><td>google</td><td>paid-display</td><td>retarget-cart-abandon-202501</td><td>banner-300x250</td></tr><tr><td>Zalo Ads</td><td>zalo</td><td>paid-social</td><td>product-zalo-202501</td><td>img-a</td></tr><tr><td>Email</td><td>email</td><td>email</td><td>promo-tet-202501</td><td>btn-cta</td></tr></tbody></table><hr><h2 id="phase-8-tracking-id-registry" tabindex="-1">Phase 8: Tracking ID Registry <a class="header-anchor" href="#phase-8-tracking-id-registry" aria-label="Permalink to &quot;Phase 8: Tracking ID Registry&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Platform</th><th>ID Type</th><th>ID Value</th><th>Status</th></tr></thead><tbody><tr><td>Facebook/Meta</td><td>Pixel ID</td><td>[from user]</td><td>Pending</td></tr><tr><td>Facebook/Meta</td><td>CAPI Access Token</td><td>[to be generated in Events Manager]</td><td>Pending</td></tr><tr><td>TikTok</td><td>Pixel ID</td><td>[from user]</td><td>Pending</td></tr><tr><td>Google Ads</td><td>Conversion ID</td><td>[from user]</td><td>Pending</td></tr><tr><td>Google Ads</td><td>Conversion Label</td><td>[from user]</td><td>Pending</td></tr><tr><td>GTM</td><td>Container ID</td><td>[from user]</td><td>Pending</td></tr><tr><td>GA4</td><td>Measurement ID</td><td>[from user if provided]</td><td>Pending</td></tr></tbody></table><hr><h2 id="phase-9-implementation-checklist" tabindex="-1">Phase 9: Implementation Checklist <a class="header-anchor" href="#phase-9-implementation-checklist" aria-label="Permalink to &quot;Phase 9: Implementation Checklist&quot;">​</a></h2><p>Phase A — GTM Foundation (Developer, 2h)</p><ul><li>[ ] Install GTM head + body snippets on all pages</li><li>[ ] Verify GTM fires on all pages via GTM Preview mode</li><li>[ ] Create all 19 GTM Variables from Phase 3 table</li><li>[ ] Create First-Touch Cookie tag (Custom HTML, All Pages, once if _ftc absent)</li><li>[ ] Test _ftc cookie in DevTools &gt; Application &gt; Cookies</li></ul><p>Phase B — Base Pixels (1h)</p><ul><li>[ ] Facebook Base Pixel tag &gt; All Pages trigger</li><li>[ ] TikTok Base Pixel tag &gt; All Pages trigger</li><li>[ ] Google Ads Remarketing tag &gt; All Pages trigger</li><li>[ ] GA4 Configuration tag &gt; All Pages trigger</li><li>[ ] Verify with platform pixel helper browser extensions</li></ul><p>Phase C — DataLayer Pushes (Developer, 2-4h)</p><ul><li>[ ] cro_purchase on order confirmation page</li><li>[ ] cro_lead on form success / thank-you</li><li>[ ] cro_view_content on product/service pages</li><li>[ ] cro_initiate_checkout on checkout page</li><li>[ ] cro_add_to_cart on cart button click</li><li>[ ] Test all pushes in GTM Preview &gt; dataLayer tab</li></ul><p>Phase D — Conversion Tags (GTM, 2h) For each [conversion event] x [active platform]: create a tag</p><ul><li>[ ] FB Purchase &gt; cro_purchase trigger</li><li>[ ] TikTok Purchase/CompletePayment &gt; cro_purchase trigger</li><li>[ ] Google Ads Purchase Conversion &gt; cro_purchase trigger</li><li>[ ] GA4 purchase event &gt; cro_purchase trigger</li><li>[ ] Repeat pattern for Lead, ViewContent, AddToCart, InitiateCheckout</li></ul><p>Phase E — Enhanced Signals (1-2h)</p><ul><li>[ ] Enable Enhanced Conversions in Google Ads settings</li><li>[ ] Add user_data to Google Ads tags (email, phone via hashed DL variables)</li><li>[ ] Configure Meta CAPI: generate Access Token in Events Manager, set up server-side</li><li>[ ] Configure TikTok Events API</li></ul><p>Phase F — QA and Verification (2h)</p><ul><li>[ ] Test purchase &gt; verify in FB Events Manager (Pixel + CAPI deduplicated)</li><li>[ ] Test lead &gt; verify in TikTok Pixel Helper</li><li>[ ] Verify Google Ads tag fires in GTM Preview</li><li>[ ] Check UTM params in GA4 &gt; Reports &gt; Acquisition</li><li>[ ] Confirm no duplicate events (each event fires once per platform)</li><li>[ ] Verify event_id deduplication: Events Manager shows &quot;Matched events&quot; count</li></ul><hr><h2 id="phase-10-common-anti-patterns-and-fixes" tabindex="-1">Phase 10: Common Anti-Patterns and Fixes <a class="header-anchor" href="#phase-10-common-anti-patterns-and-fixes" aria-label="Permalink to &quot;Phase 10: Common Anti-Patterns and Fixes&quot;">​</a></h2><p>Anti-pattern: Pixel fires a second Purchase event from base pixel tag Fix: Use GTM trigger exceptions or sequencing to prevent base pixel re-firing on conversion page.</p><p>Anti-pattern: Missing event_id causes CAPI double-counting Fix: Generate one UUID server-side, send to both browser dataLayer and CAPI payload with the same value.</p><p>Anti-pattern: UTM parameters lost on redirect (session shows direct) Fix: Capture UTM on first page load immediately into _ftc cookie. Never rely on document.referrer.</p><p>Anti-pattern: Pixel fires before dataLayer.push() completes (empty parameters) Fix: Use Custom Event trigger keyed to cro_purchase, not Page View. GTM waits for the push.</p><p>Anti-pattern: value sent as string not number (breaks revenue reporting) Fix: Always parseFloat(orderTotal) before pushing to dataLayer.</p><p>Anti-pattern: Not passing hashed email/phone on conversions (CAPI match rate drops) Fix: SHA256 hash and pass em/ph on every purchase and lead event.</p><p>Anti-pattern: Cross-domain tracking broken (landing page to checkout subdomain) Fix: Configure GTM cross-domain linker + add both domains to GA4 configuration.</p><hr><h2 id="output-format" tabindex="-1">Output Format <a class="header-anchor" href="#output-format" aria-label="Permalink to &quot;Output Format&quot;">​</a></h2><p>Save the complete strategy as: tracking-strategy-[brand]-[YYYYMMDD].md</p><p>The document must be so specific that a developer can implement without asking a single follow-up question. Every tag, trigger, variable, and dataLayer push must be fully specified using the user&#39;s exact IDs and event names.</p><p>Include a Quick Reference Card at the end (1-page summary):</p><ul><li>All tracking IDs in one table</li><li>DataLayer event names cheat sheet</li><li>UTM convention quick reference</li><li>Top 3 priority events to implement first (ranked by algorithm impact)</li></ul><p>After saving, use present_files if available, otherwise share file link.</p><p>Offer follow-up options:</p><ol><li>&quot;Muốn tôi tạo GTM Container JSON spec để import thẳng không?&quot;</li><li>&quot;Muốn tôi tạo CAPI server-side implementation guide riêng không?&quot;</li><li>&quot;Cần Google Sheets template theo dõi UTM convention cho cả team không?&quot;</li></ol>',60))])}const y=d(n,[["render",c]]);export{b as __pageData,y as default};
